# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(transactions):
    account_balances = {}

    for transaction in transactions:
        account, amount = transaction

        if account not in account_balances:
            account_balances[account] = 0

        account_balances[account] += amount

    return account_balances

# Example usage:
transactions = [
    ('Alice', 100),
    ('Bob', -50),
    ('Alice', 200),
    ('Charlie', 300),
    ('Bob', -150)
]

updated_balances = process_transactions(transactions)
print(updated_balances)